channels = get_channels()
if len(channels) == 0:
    raise ValueError("No channels found.")

all_messages = [message for channel in channels for message in read_channel_messages(channel)]
if len(all_messages) == 0:
    raise ValueError("No channel messages found.")

message_counts = {}
for message in all_messages:
    sender = message.sender
    message_counts = {**message_counts, sender: message_counts.get(sender, 0) + 1}

most_active_user = None
most_active_count = None
for sender, count in message_counts.items():
    if most_active_count is None or count > most_active_count:
        most_active_user = sender
        most_active_count = count

if most_active_user is None:
    raise ValueError("Could not determine the most active user.")

send_direct_message(recipient=most_active_user, body="Congrats on being the most active user!")
print("Sent message to {}".format(most_active_user))
